import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link } from 'react-router-dom';
import { registerUser } from '../redux/thunks/authThunks';
import { clearError } from '../redux/slices/authSlice';
import { toast } from 'react-toastify';
import './Register.css';

const Register = () => {
  const [fullName, setFullName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading, error } = useSelector((state) => state.auth);

  useEffect(() => {
    if (error) {
      toast.error(error);
      dispatch(clearError());
    }
  }, [error, dispatch]);

  const validateEmail = (val) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val);
  };

  const handleRegister = (e) => {
    e.preventDefault();

    if (!fullName.trim()) {
      toast.warn('Please enter your full name');
      return;
    }
    if (!email || !validateEmail(email)) {
      toast.warn('Please enter a valid email address');
      return;
    }
    if (!password || password.length < 6) {
      toast.warn('Password must be at least 6 characters');
      return;
    }
    if (password !== confirmPassword) {
      toast.warn('Passwords do not match');
      return;
    }

    const nameParts = fullName.trim().split(' ');
    const firstName = nameParts[0];
    const lastName = nameParts.slice(1).join(' ') || '';

    dispatch(registerUser({
      firstName,
      lastName,
      email,
      password,
      fullName: fullName.trim(),
    }));
  };

  return (
    <div className="register-screen">
      <div className="register-container">
        <div className="register-logo-section">
          <div className="register-logo">FL</div>
          <h1 className="register-title">Create Your FriendLinq Account</h1>
        </div>

        <form onSubmit={handleRegister} className="register-form">
          <input
            type="text"
            className="register-input"
            placeholder="Enter your full name"
            value={fullName}
            onChange={(e) => setFullName(e.target.value)}
            autoComplete="name"
          />

          <input
            type="email"
            className="register-input"
            placeholder="Enter your email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            autoComplete="email"
          />

          <div className="register-password-wrap">
            <input
              type={showPassword ? 'text' : 'password'}
              className="register-password-input"
              placeholder="Create a strong password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              autoComplete="new-password"
            />
            <button
              type="button"
              className="register-eye-btn"
              onClick={() => setShowPassword(!showPassword)}
              aria-label="Toggle password visibility"
            >
              {showPassword ? '👁' : '👁‍🗨'}
            </button>
          </div>

          <div className="register-password-wrap">
            <input
              type={showConfirmPassword ? 'text' : 'password'}
              className="register-password-input"
              placeholder="Confirm your password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              autoComplete="new-password"
            />
            <button
              type="button"
              className="register-eye-btn"
              onClick={() => setShowConfirmPassword(!showConfirmPassword)}
              aria-label="Toggle confirm password visibility"
            >
              {showConfirmPassword ? '👁' : '👁‍🗨'}
            </button>
          </div>

          <button
            type="submit"
            className="register-btn-primary"
            disabled={loading}
          >
            {loading ? 'Creating Account...' : 'Next'}
          </button>
        </form>

        <div className="register-login-row">
          <span>Already have an account? </span>
          <Link to="/login" className="register-login-link">Login</Link>
        </div>
      </div>
    </div>
  );
};

export default Register;
